function ToolList() {
  const { section, div, h2, p, span } = tags;
  const colors = ['#F58882', '#FDA303', '#0AF3EB', '#00E0AB', '#FCD021', '#FC8D0D', '#6500C6', '#FE4474', '#D80F4A'];
  const tools = [
    { name: 'decantr_read_essence', desc: 'Read the current essence spec from the working directory' },
    { name: 'decantr_validate', desc: 'Validate an essence file against the schema and guard rules' },
  ];

  return section({ class: css('_py30 _relative _z1') },
    div({ class: css('_container') },
      h2({ class: css('_heading2 _text[center] _mb4') }, 'MCP Tools'),
      p({ class: css('_text[center] _fgmuted _mx[auto] _mb14') }, '10 tools available via MCP.'),
      div({ class: css('_grid _gc2 _gap0 _mw[880px] _mx[auto]') },
        tools.map((t, i) => {
          const color = colors[i % colors.length];
          return div({ class: css('_py4 _px5 _pl9 _borderbottom _borderbottom[rgba(255,255,255,0.06)] _transition _bgwhite/2 _hover:bgwhite/5 _relative'), style: `border-left:4px solid ${color}` },
            div({ class: css('_flex _items[center] _gap2 _mono _fs[0.82rem] _fw600 _mb1'), style: `color:${color}` },
              span({ class: css('_w[6px] _h[6px] _rounded[50%] _inline-block _shrink0'), style: `background:${color}` }),
              t.name
            ),
            div({ class: css('_fs[0.82rem] _fgmuted _lh[1.4]') }, t.desc)
          );
        })
      )
    )
  );
}

